        background-color: #ffffff;
        padding: 30px 25px;        /* Adjusted padding */
        border-radius: 8px;        /* Matched to typical modern card radius */
        box-shadow: 0 4px 15px rgba(0, 0, 0, 0.08); /* Softer, more subtle shadow */
        text-align: center;
        max-width: 480px;          /* Adjusted max-width, can be tweaked */
        width: 100%;
        margin: 30px auto;         /* More vertical margin for spacing */
        direction: rtl;
        overflow: hidden;
        font-family: inherit; /* Inherit font from your theme */
    }

    .newsletter-cta-card h2 {
        color: #1448B8;
        margin-top: 0;
        margin-bottom: 25px;
        font-size: 1.6em;          /* Adjust to match visual hierarchy */
        line-height: 1.45;
        font-weight: 600;         /* Or match your site's heading weight */
    }

    .newsletter-cta-card .fluentform-placeholder {
        margin-top: 15px;
    }

    /* Styling for Fluent Form elements within this card */
    /* Note: Fluent Forms often has its own label structure. 
       The label "البريد الالكتروني *" should be configured IN Fluent Forms. */

    .newsletter-cta-card .ff-el-input--content label, /* Common Fluent Form label selector */
    .newsletter-cta-card .fluentform .ff-el-input-label label /* Another common selector */
    {
        display: block;
        text-align: right; /* Align label text to the right */
        font-size: 0.95em;
        color: #333;
        margin-bottom: 8px; /* Space between label and input */
        font-weight: 500;
    }

    .newsletter-cta-card .ff-el-input--content label .ff-el-required-indicator, /* Required asterisk */
    .newsletter-cta-card .fluentform .ff-el-input-label label .ff-el-required-indicator {
        color: red;
        margin-right: 3px;
    }


    .newsletter-cta-card .ff-el-form-control { /* Common class for Fluent Form input fields */
        width: 100%;
        padding: 10px 12px;
        margin-bottom: 20px;       /* Space below input before button */
        border: 1px solid #dcdcdc; /* Slightly softer border color */
        border-radius: 5px;        /* Matched radius */
        box-sizing: border-box;
        font-size: 1em;
        text-align: right; /* Align input text to the right */
    }

    .newsletter-cta-card .ff-el-form-control:focus {
        border-color: #1448B8;
        box-shadow: 0 0 0 0.15rem rgba(20, 72, 184, 0.2); /* Adjusted focus ring */
        outline: none;
    }

    .newsletter-cta-card .ff-btn-submit,
    .newsletter-cta-card input[type="submit"] {
        background-color: #1448B8;
        color: white;
        border: none;
        padding: 12px 20px;
        text-align: center;
        text-decoration: none;
        display: block;            /* Make button full width */
        width: 100%;               /* Make button full width */
        box-sizing: border-box;    /* Include padding and border in the element's total width and height */
        font-size: 1.1em;
        font-weight: 500;
        margin-top: 10px;          /* Adjusted margin-top */
        cursor: pointer;
        border-radius: 5px;        /* Matched radius */
        transition: background-color 0.3s ease, transform 0.2s ease;
    }

    .newsletter-cta-card .ff-btn-submit:hover,
    .newsletter-cta-card input[type="submit"]:hover {
        background-color: #0f3a9a;
        transform: translateY(-1px); /* Slightly less lift */
    }

.newsletter-cta-card .ff-el-input--content label .ff-el-required-indicator,
.newsletter-cta-card .fluentform .ff-el-input-label label .ff-el-required-indicator {
    display: none !important;
